class TestReadDailyCost:
    def test_empty_dir(self, tmp_path, monkeypatch):
        today_dir = tmp_path / "session-tracker" / "2026-03-28"
        today_dir.mkdir(parents=True)
        monkeypatch.setattr(config, "SESSION_TRACKER_DIR", tmp_path / "session-tracker")
        result = read_daily_cost()
        assert result == 0.0

    def test_missing_dir(self, tmp_path, monkeypatch):
        monkeypatch.setattr(config, "SESSION_TRACKER_DIR", tmp_path / "nonexistent")
        result = read_daily_cost()
        assert result == 0.0

    def test_sums_valid_files(self, tmp_path, monkeypatch):
        import datetime

        today = datetime.date.today().isoformat()
        today_dir = tmp_path / "session-tracker" / today
        today_dir.mkdir(parents=True)

        (today_dir / "a.json").write_text(
            json.dumps({"cost": {"total_cost_usd": 1.50}}), encoding="utf-8"
        )
        (today_dir / "b.json").write_text(
            json.dumps({"cost": {"total_cost_usd": 2.75}}), encoding="utf-8"
        )

        monkeypatch.setattr(config, "SESSION_TRACKER_DIR", tmp_path / "session-tracker")
        result = read_daily_cost()
        assert abs(result - 4.25) < 0.001

    def test_skips_malformed_json(self, tmp_path, monkeypatch):
        import datetime

        today = datetime.date.today().isoformat()
        today_dir = tmp_path / "session-tracker" / today
        today_dir.mkdir(parents=True)

        (today_dir / "good.json").write_text(
            json.dumps({"cost": {"total_cost_usd": 3.00}}), encoding="utf-8"
        )
        (today_dir / "bad.json").write_text("not json{{{", encoding="utf-8")

        monkeypatch.setattr(config, "SESSION_TRACKER_DIR", tmp_path / "session-tracker")
        result = read_daily_cost()
        assert abs(result - 3.00) < 0.001

    def test_handles_missing_cost_field(self, tmp_path, monkeypatch):
        import datetime

        today = datetime.date.today().isoformat()
        today_dir = tmp_path / "session-tracker" / today
        today_dir.mkdir(parents=True)

        (today_dir / "no_cost.json").write_text(json.dumps({"foo": "bar"}), encoding="utf-8")

        monkeypatch.setattr(config, "SESSION_TRACKER_DIR", tmp_path / "session-tracker")
        result = read_daily_cost()
        assert result == 0.0

    def test_handles_null_cost(self, tmp_path, monkeypatch):
        import datetime

        today = datetime.date.today().isoformat()
        today_dir = tmp_path / "session-tracker" / today
        today_dir.mkdir(parents=True)

        (today_dir / "null.json").write_text(
            json.dumps({"cost": {"total_cost_usd": None}}), encoding="utf-8"
        )

        monkeypatch.setattr(config, "SESSION_TRACKER_DIR", tmp_path / "session-tracker")
        result = read_daily_cost()
        assert result == 0.0


class TestReadUsageLimits:
    def test_missing_file(self, tmp_path, monkeypatch):
        monkeypatch.setattr(config, "OAUTH_USAGE_CACHE", tmp_path / "nonexistent.json")
        result = read_usage_limits()
        assert result == {}

    def test_valid_file(self, tmp_path, monkeypatch):
        cache_file = tmp_path / "oauth_usage.json"
        data = {
            "five_hour": {"utilization": 23.5, "resets_at": "2026-03-28T12:00:00Z"},
            "seven_day": {"utilization": 45.0, "resets_at": "2026-04-01T00:00:00Z"},
        }
        cache_file.write_text(json.dumps(data), encoding="utf-8")
        monkeypatch.setattr(config, "OAUTH_USAGE_CACHE", cache_file)

        result = read_usage_limits()
        assert result["five_hour"]["utilization"] == 23.5
        assert result["seven_day"]["utilization"] == 45.0

    def test_malformed_json(self, tmp_path, monkeypatch):
        cache_file = tmp_path / "oauth_usage.json"
        cache_file.write_text("not json{{{", encoding="utf-8")
        monkeypatch.setattr(config, "OAUTH_USAGE_CACHE", cache_file)

        result = read_usage_limits()
        assert result == {}

    def test_non_dict_json(self, tmp_path, monkeypatch):
        cache_file = tmp_path / "oauth_usage.json"
        cache_file.write_text(json.dumps([1, 2, 3]), encoding="utf-8")
        monkeypatch.setattr(config, "OAUTH_USAGE_CACHE", cache_file)

        result = read_usage_limits()
        assert result == {}
